    {
        _statusStrip = new StatusStrip();
        // .NET 9: StatusStrip default renderer changed; set explicitly to preserve appearance
        _statusStrip.RenderMode = ToolStripRenderMode.System;
        Controls.Add(_statusStrip);
    }

    // .NET 9 WFO1000: properties on UserControl must have explicit serialization configuration
    [DefaultValue("")]
    public string DisplayName { get; set; } = "";

    [DefaultValue(0)]
    public int MaxItems { get; set; }

    /// <summary>
    /// Shows a drop-down editor. In .NET 9 the DropDownControl parameter became non-nullable,
    /// so callers that previously passed null must guard against it.
    /// </summary>
    public void ShowDropDown(IWindowsFormsEditorService editorService, Control? control)
    {
        if (control is not null)
        {
            editorService.DropDownControl(control);
        }
    }
}

